function updu_enqueue_scripts() {
    wp_enqueue_script('jquery');
}

add_action('wp_enqueue_scripts', 'updu_enqueue_scripts');

function updu_upload_form() {
    if (is_user_logged_in()) {
        echo '<form id="updu-upload-form" method="post" enctype="multipart/form-data">
                <input type="file" name="updu_file" required>
                <input type="submit" name="updu_submit" value="Upload">
              </form>';
    } else {
        echo 'Please log in to upload files.';
    }
}

add_shortcode('updu_upload_form', 'updu_upload_form');

function updu_handle_upload() {
    if (isset($_POST['updu_submit']) && !empty($_FILES['updu_file'])) {
        $upload_dir = wp_upload_dir();
        $target_dir = $upload_dir['basedir'] . '/user-files/';
        
        if (!file_exists($target_dir)) {
            wp_mkdir_p($target_dir);
        }

        $file = $_FILES['updu_file'];
        $file_name = basename($file['name']);
        $target_file = $target_dir . $file_name;
        $file_type = wp_check_filetype($file_name);

        $allowed_types = array('jpg', 'jpeg', 'png', 'gif', 'pdf', 'doc', 'docx');

        if (in_array($file_type['ext'], $allowed_types)) {
            if (move_uploaded_file($file['tmp_name'], $target_file)) {
                echo 'File uploaded successfully.';
            } else {
                echo 'There was an error uploading your file.';
            }
        } else {
            echo 'File type not allowed.';
        }
    }
}

add_action('init', 'updu_handle_upload');
